package org.example.aop.aspectj

import com.intellij.psi.PsiElement
import com.intellij.psi.PsiReferenceBase

internal class AspectJNamedPointcutReference(
    element: PsiElement
) : PsiReferenceBase<PsiElement>(element, true) {

    override fun resolve(): PsiElement? {
        val file = element.containingFile
        val pointcutName = element.text

        val psiDecl = AspectJReferenceSupport.findPointcutDeclaration(file, pointcutName)
        if (psiDecl != null) {
            return psiDecl.nameIdentifier
        }

        val projectDecl = AspectJReferenceSupport.findPointcutDeclarationInProject(file.project, pointcutName)
        if (projectDecl != null) return projectDecl.nameIdentifier

        // Fallback to regex-based approach for compatibility
        val declarationOffset = AspectJReferenceSupport.findPointcutDeclarationOffset(file.text, pointcutName) ?: return null
        return file.findElementAt(declarationOffset)
    }

    override fun getVariants(): Array<Any> = emptyArray()
}

package org.example.aop.aspectj

import com.intellij.util.indexing.DataIndexer
import com.intellij.util.indexing.FileBasedIndexExtension
import com.intellij.util.indexing.FileContent
import com.intellij.util.indexing.ID
import com.intellij.util.indexing.FileBasedIndex
import com.intellij.util.io.EnumeratorStringDescriptor

/**
 * Indexes named AspectJ pointcuts so references can resolve across files.
 */
class AspectJPointcutIndex : FileBasedIndexExtension<String, Void>() {

	companion object {
		val NAME: ID<String, Void> = ID.create("org.example.aop.aspectj.pointcut.index")
		private val POINTCUT_REGEX = Regex("""(?m)^\s*pointcut\s+([A-Za-z_][A-Za-z0-9_]*)\s*\(""")
	}

	override fun getName(): ID<String, Void> = NAME

	override fun getVersion(): Int = 1

	override fun getIndexer(): DataIndexer<String, Void, FileContent> = DataIndexer { inputData ->
		POINTCUT_REGEX.findAll(inputData.contentAsText).associate { match ->
			match.groupValues[1] to null
		}
	}

	override fun getKeyDescriptor() = EnumeratorStringDescriptor.INSTANCE

	override fun getValueExternalizer() = com.intellij.util.io.VoidDataExternalizer.INSTANCE

	override fun getInputFilter() = com.intellij.util.indexing.FileBasedIndex.InputFilter { file ->
		file.extension == "aj"
	}

	override fun dependsOnFileContent(): Boolean = true

	override fun getCacheSize() = 1024
}

package org.example.aop.aspectj

import com.intellij.codeInspection.LocalQuickFix
import com.intellij.codeInspection.ProblemDescriptor
import com.intellij.openapi.project.Project
import com.intellij.psi.PsiElement
import com.intellij.psi.PsiFileFactory
import com.intellij.psi.util.PsiTreeUtil
import com.intellij.openapi.command.WriteCommandAction
import org.example.aop.aspectj.psi.PointcutDeclaration

class CreatePointcutQuickFix(private val name: String) : LocalQuickFix {
    override fun getName(): String = "Create pointcut '$name'"
    override fun getFamilyName(): String = "AspectJ quick fixes"

    override fun applyFix(project: Project, descriptor: ProblemDescriptor) {
        val element = descriptor.psiElement ?: return
        val file = element.containingFile ?: return

        // Create a new pointcut declaration stub and append it to the file using the document API.
        val text = "\npointcut $name() : ;\n"
        WriteCommandAction.runWriteCommandAction(project) {
            val document = com.intellij.psi.PsiDocumentManager.getInstance(project).getDocument(file)
            if (document != null) {
                document.insertString(document.textLength, text)
                com.intellij.psi.PsiDocumentManager.getInstance(project).commitDocument(document)
            } else {
                // Fallback to PSI-based insertion if document is not available
                val factory = PsiFileFactory.getInstance(project)
                val dummy = factory.createFileFromText("__tmp.aj", AspectJFileType, text)
                val decl = PsiTreeUtil.findChildOfType(dummy, PointcutDeclaration::class.java)
                if (decl != null) {
                    file.addAfter(decl, file.lastChild)
                }
            }
        }
    }
}

