// ============================================================================
// Base PSI Elements
// ============================================================================

abstract class AspectJPsiElement(node: ASTNode) : ASTWrapperPsiElement(node)

// ============================================================================
// File-level Elements
// ============================================================================

class AspectDeclaration(node: ASTNode) : AspectJPsiElement(node) {
	fun getAspectName(): String? {
		var child = firstChild
